local LxBaseCtrl = require("LApp.controller.LxBaseCtrl")
---@class LxInsCtrl:LxBaseCtrl
local LxInsCtrl = classX("LxInsCtrl", LxBaseCtrl)

local typeOfEventAreaObject = typeof(ProjectX.CEventAreaObject)

local _InsCtrlTimer = {
    FrameRun = 1,
}

function LxInsCtrl:ctor()
    LxBaseCtrl.ctor(self)

    ---@type LCityView
    self._cityView = nil

    self._param = nil
end

function LxInsCtrl:Initialize()
    LxBaseCtrl.Initialize(self)
end

function LxInsCtrl:Dispose()
    self:ClearCityView()

    LxBaseCtrl.Dispose(self)
end

function LxInsCtrl:InitEvents()
    self:AddEventHandler(EventNames.CITY_JOYSTICK_END, self.OnJoyStickEnd, self)
    self:AddEventHandler(EventNames.CITY_JOYSTICK_MOVE, self.OnJoyStickMove, self)
    self:AddEventHandler(EventNames.INSTANCE_REFRESHPOINT, self.OnRefreshPoint, self)
end

function LxInsCtrl:SetParam(param)
    self._param = param
    ---@type LxInstanceStoryObj
    local storyObj = ModuleCenter.Instance:GetStoryObj(param.storyRefId)
    if not storyObj then return end
    ShowPanel(UiNames.InstanceWorld,{storyObj = storyObj})
end

function LxInsCtrl:ClearCityView()
    self:RemoveTouchList()
    self:RemoveEventHandlerList()
    self:StopTimer(_InsCtrlTimer.FrameRun)
    self._touchNpc = nil
    if self._cityView then
        self._cityView:Dispose()
        self._cityView = nil
    end
end

function LxInsCtrl:InitCityView()
    self:InitTouchs()
    self:InitEvents()

    self._cityView = require("LApp.gameplay.city.view.LCityView"):new()
    self._cityView:Initialize()
    self._cityView:InitView(CityTypeEnum.ins)
    self._cityView:ShowMainRole()

    self:RefreshEventAreas()

    self:StartTimer(_InsCtrlTimer.FrameRun, 0, true, -1, function() self:OnUpdate()  end)
end

function LxInsCtrl:RefreshEventAreas()
    if not self._param then return end

    if not self._cityView then return end

    local storyRefId = self._param.storyRefId
    if not storyRefId then return end

    local storyObj = ModuleCenter.Instance:GetStoryObj(storyRefId)
    if not storyObj then return end

    ---@type table<number,LxInstancePointObj>
    local pointMap = {}
    local recordFinishPMap = {}
    local cityView = self._cityView
    local pointRef = GameTable.InsPointRef
    local ref
    for targetId,targetObj in pairs(storyObj.targetObjs) do
        for pointId,pointObj in pairs(targetObj.pointObj) do
            pointMap[pointId] = pointObj
            recordFinishPMap[pointId] = pointObj.finish
        end
    end
    local pointList = {}
    for k,v in pairs(pointMap) do
        table.insert(pointList,v)
    end
    table.sort(pointList,function(a,b)
        return a.refId < b.refId
    end)
    local pointId
    local recordPointMap = {}
    for i,pointObj in ipairs(pointList) do
        pointId = pointObj.refId
        if not recordPointMap[pointId] then
            ref = pointRef[pointId]
            if ref then
                local bShow = checknumber(ref.initialShow) == 0
                if not bShow then
                    if recordFinishPMap[pointId] then
                        bShow = true
                        recordPointMap[pointId] = true
                    else
                        local show = ref.show
                        if not string.isempty(show) then
                            local showData = string.split(show,"=")
                            local tPointId = checknumber(showData[2])
                            if not recordPointMap[tPointId] then
                                local tFinish = recordFinishPMap[tPointId] and true or false
                                bShow = tFinish
                                cityView:SetEventAreaShow(pointId,tFinish)
                                recordPointMap[pointId] = true
                            end
                        end
                        local showNext = ref.showNext
                        if showNext and #showNext > 0 then
                            for i,tPointId in ipairs(showNext) do
                                tPointId = checknumber(tPointId)
                                if not recordPointMap[tPointId] then
                                    local tFinish = recordFinishPMap[tPointId] and true or false
                                    if tPointId == pointId then
                                        bShow = true
                                    end
                                    cityView:SetEventAreaShow(tPointId,tFinish)
                                    recordPointMap[tPointId] = true
                                end
                            end
                        end
                    end
                end
                cityView:SetEventAreaShow(pointId,bShow)
            end
        end
    end
end

function LxInsCtrl:OnUpdate()
    if self._cityView then
        self._cityView:OnUpdate(Time.deltaTime)
    end
end

function LxInsCtrl:InitTouchs()
    self:AddTouch(TouchNames.On_TouchStart,self.OnTouchStart, self)
    self:AddTouch(TouchNames.On_TouchUp,self.OnTouchUp, self)
end

---@param gesture Gesture
function LxInsCtrl:OnTouchStart(gesture)
    if not self._cityView then return end
    local position = gesture.position
    local go = PJXUtil.TouchHitObject(gesture.position, gesture.fingerIndex)
    --if go and go.name == "MapRoot" then
    --    local worldPos = LxUiHelper.GetSceneCamera():ScreenToWorldPoint(Vector3(position.x, position.y,0))
    --    self._cityView:OnTouchPos(worldPos)
    --end

    if go and string.startswith(go.name, "Npc") then
        self._touchNpc = go
        go.transform.localScale = Vector3.New(0.98,0.98,0.98)
    end

    if go then
        local com = go:GetComponent(typeOfEventAreaObject)
        if com then
            self._touchNpc = go
            go.transform.localScale = Vector3.New(0.98,0.98,0.98)
            return
        end
    end

end

---@param gesture Gesture
function LxInsCtrl:OnTouchUp(gesture)
    local touchNpc = self._touchNpc
    self._touchNpc = nil
    if touchNpc then
        touchNpc.transform.localScale = Vector3.one
    end

    local gos = PJXUtil.TouchHitObjects(gesture.position, gesture.fingerIndex)
    if gos and gos.Count > 0 then
        local count = gos.Count - 1
        local go
        for i=0, count do
            go = gos[i]
            if go and touchNpc == go then
                self:OnClickNpc(go)
                break
            end
        end
    end
end

function LxInsCtrl:OnClickNpc(go)
    local com = go:GetComponent(typeOfEventAreaObject)
    if com then
        local eventId = com.eventId
        self._cityView:OnClickEventArea(eventId,self._param)
    end
end

function LxInsCtrl:OnJoyStickStart()
    if not self._cityView then return end
    self._cityView:DoJoyStickStart()
end

function LxInsCtrl:OnJoyStickMove(pos,deltaTime)
    if not self._cityView then return end
    self._cityView:DoJoyStickMove(pos,deltaTime)
end

function LxInsCtrl:OnJoyStickEnd()
    if not self._cityView then return end
    self._cityView:DoJoyStickEnd()

end

function LxInsCtrl:OnRefreshPoint()
    self:RefreshEventAreas()
end

return LxInsCtrl